import { encodeSudoku } from '@sudoku/sencode';
import { derived } from 'svelte/store';
import { hints } from './hints';
import { gameSession } from './session';

const emptyGrid = () => Array.from({ length: 9 }, () => Array(9).fill(0));

// 从 session 快照投影出题面网格和用户网格的派生 store
const gridView = derived(gameSession, ($session) => $session?.baseGrid ?? emptyGrid());
const userGridView = derived(gameSession, ($session) => $session?.userGrid ?? emptyGrid());

function createGrid() {
	return {
		subscribe: gridView.subscribe,

		generate(difficulty) {
			return gameSession.generate(difficulty);
		},

		decodeSencode(sencode) {
			return gameSession.decodeSencode(sencode);
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

function createUserGrid() {
	return {
		subscribe: userGridView.subscribe,

		set(pos, value) {
			return gameSession.guess({
				row:   pos.y,
				col:   pos.x,
				value,
			});
		},

		applyHint(pos) {
			const applied = gameSession.applyHint(pos);

			if (applied) {
				hints.useHint();
			}

			return applied;
		},

		undo() {
			return gameSession.undo();
		},

		redo() {
			return gameSession.redo();
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(gameSession, ($session) => $session?.invalidCells ?? [], []);
